#ifdef BLOCK_SIZE
#define LOCAL_SIZE BLOCK_SIZE
#else
#define LOCAL_SIZE 16
#endif

__kernel void 
lud_diagonal(__global float *m, int matrix_dim, int offset)
{
  int i, j;
  __local float shadow[LOCAL_SIZE][LOCAL_SIZE];
  int local_id = get_local_id(0);

  int array_offset = offset * matrix_dim + offset;
  for (i = 0; i < LOCAL_SIZE; i++) {
    shadow[i][local_id] = m[array_offset + local_id];
    array_offset += matrix_dim;
  }
  __syncthreads();

  for (i = 0; i < LOCAL_SIZE - 1; i++) {
    if (local_id > i) {
      float sum = 0.0f;
      for (j = 0; j < i; j++) {
        sum += shadow[local_id][j] * shadow[j][i];
      }
      shadow[local_id][i] -= sum;
      shadow[local_id][i] /= shadow[i][i];
    }
    __syncthreads();

    if (local_id > i) {
      float sum = 0.0f;
      for (j = 0; j < i + 1; j++) {
        sum += shadow[i + 1][j] * shadow[j][local_id];
      }
      shadow[i + 1][local_id] -= sum;
    }
    __syncthreads();
  }

  array_offset = (offset + 1) * matrix_dim + offset;
  for (i = 1; i < LOCAL_SIZE; i++) {
    m[array_offset + local_id] = shadow[i][local_id];
    array_offset += matrix_dim;
  }
}

__kernel void
lud_perimeter(__global float *m, int matrix_dim, int offset)
{
  __local float dia[LOCAL_SIZE][LOCAL_SIZE];
  __local float peri_row[LOCAL_SIZE][LOCAL_SIZE];
  __local float peri_col[LOCAL_SIZE][LOCAL_SIZE];

  int i, j, array_offset;
  int idx;
  int local_id = get_local_id(0);
  int group_id = get_group_id(0);

  if (local_id < LOCAL_SIZE) {
    idx = local_id;

    array_offset = offset * matrix_dim + offset;
    for (i = 0; i < LOCAL_SIZE / 2; i++) {
      dia[i][idx] = m[array_offset + idx];
      array_offset += matrix_dim;
    }

    array_offset = offset * matrix_dim + offset;
    for (i = 0; i < LOCAL_SIZE; i++) {
      peri_row[i][idx] = m[array_offset + (group_id + 1) * LOCAL_SIZE + idx];
      array_offset += matrix_dim;
    }
  } else {
    idx = local_id - LOCAL_SIZE;

    array_offset = (offset + LOCAL_SIZE / 2) * matrix_dim + offset;
    for (i = LOCAL_SIZE / 2; i < LOCAL_SIZE; i++) {
      dia[i][idx] = m[array_offset + idx];
      array_offset += matrix_dim;
    }

    array_offset = (offset + (group_id + 1) * LOCAL_SIZE) * matrix_dim + offset;
    for (i = 0; i < LOCAL_SIZE; i++) {
      peri_col[i][idx] = m[array_offset + idx];
      array_offset += matrix_dim;
    }
  }
  __syncthreads();

  if (local_id < LOCAL_SIZE) {
    idx = local_id;
    for (i = 1; i < LOCAL_SIZE; i++) {
      float sum = 0.0f;
      for (j = 0; j < i; j++) {
        sum += dia[i][j] * peri_row[j][idx];
      }
      peri_row[i][idx] -= sum;
    }
  } else {
    idx = local_id - LOCAL_SIZE;
    for (i = 0; i < LOCAL_SIZE; i++) {
      float sum = 0.0f;
      for (j = 0; j < i; j++) {
        sum += peri_col[idx][j] * dia[j][i];
      }
      peri_col[idx][i] -= sum;
      peri_col[idx][i] /= dia[i][i];
    }
  }

  __syncthreads();

  if (local_id < LOCAL_SIZE) {
    idx = local_id;
    array_offset = (offset + 1) * matrix_dim + offset;
    for (i = 1; i < LOCAL_SIZE; i++) {
      m[array_offset + (group_id + 1) * LOCAL_SIZE + idx] = peri_row[i][idx];
      array_offset += matrix_dim;
    }
  } else {
    idx = local_id - LOCAL_SIZE;
    array_offset = (offset + (group_id + 1) * LOCAL_SIZE) * matrix_dim + offset;
    for (i = 0; i < LOCAL_SIZE; i++) {
      m[array_offset + idx] = peri_col[i][idx];
      array_offset += matrix_dim;
    }
  }
}

__kernel void
lud_internal(__global float *m, int matrix_dim, int offset)
{
  __local float peri_row[LOCAL_SIZE][LOCAL_SIZE];
  __local float peri_col[LOCAL_SIZE][LOCAL_SIZE];

  int i;
  float sum;
  int local_x = get_local_id(0);
  int local_y = get_local_id(1);
  int group_x = get_group_id(0);
  int group_y = get_group_id(1);

  int global_row_id = offset + (group_y + 1) * LOCAL_SIZE;
  int global_col_id = offset + (group_x + 1) * LOCAL_SIZE;

  peri_row[local_y][local_x] = m[(offset + local_y) * matrix_dim + global_col_id + local_x];
  peri_col[local_y][local_x] = m[(global_row_id + local_y) * matrix_dim + offset + local_x];

  __syncthreads();

  sum = 0.0f;
  for (i = 0; i < LOCAL_SIZE; i++) {
    sum += peri_col[local_y][i] * peri_row[i][local_x];
  }
  m[(global_row_id + local_y) * matrix_dim + global_col_id + local_x] -= sum;
}
